function Badge({ children, color = C.accent }) {
  return <span style={{ display: "inline-block", padding: "3px 10px", borderRadius: "16px", fontSize: "11.5px", fontWeight: 600, background: `${color}12`, color, border: `1px solid ${color}25`, letterSpacing: "0.01em" }}>{children}</span>;
}

function MetricBox({ metric, label, color = C.accent }) {
  return (
    <div style={{ textAlign: "center", padding: "18px 14px", background: C.white, borderRadius: "12px", border: `1px solid ${C.border}`, boxShadow: "0 1px 3px rgba(0,0,0,0.04)" }}>
      <div style={{ fontSize: "26px", fontWeight: 800, color, fontFamily: "'Space Mono', monospace" }}>{metric}</div>
      <div style={{ fontSize: "12px", color: C.textMuted, marginTop: "4px", lineHeight: 1.4 }}>{label}</div>
    </div>
  );
}

function Section({ children, sub }) {
  return (
    <div style={{ marginBottom: "36px" }}>
      <h2 style={{ fontSize: "clamp(26px, 3.5vw, 36px)", fontWeight: 800, color: C.text, fontFamily: "'Syne', sans-serif", margin: 0, letterSpacing: "-0.02em" }}>{children}</h2>
      {sub && <p style={{ color: C.textMuted, fontSize: "15px", marginTop: "6px", maxWidth: "560px" }}>{sub}</p>}
      <div style={{ width: "48px", height: "3px", background: `linear-gradient(90deg, ${C.accent}, ${C.accent}40)`, marginTop: "14px", borderRadius: "2px" }} />
    </div>
  );
}

function ProjCard({ p, onClick }) {
  const [h, setH] = useState(false);
  return (
    <div onClick={onClick} onMouseEnter={() => setH(true)} onMouseLeave={() => setH(false)} style={{
      background: C.white, border: `1px solid ${h ? p.color + "40" : C.border}`, borderRadius: "14px", padding: "24px", cursor: "pointer",
      transition: "all 0.25s", transform: h ? "translateY(-3px)" : "none", boxShadow: h ? `0 8px 24px ${p.color}12` : "0 1px 3px rgba(0,0,0,0.04)",
    }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: "10px" }}>
        <div style={{ width: "36px", height: "36px", borderRadius: "9px", background: `${p.color}10`, display: "flex", alignItems: "center", justifyContent: "center" }}>
          <div style={{ width: "10px", height: "10px", borderRadius: "50%", background: p.color }} />
        </div>
        <span style={{ fontSize: "11px", color: C.textDim, fontWeight: 500 }}>{p.date}</span>
      </div>
      <h3 style={{ fontSize: "18px", fontWeight: 700, color: C.text, margin: "0 0 3px", fontFamily: "'Syne', sans-serif" }}>{p.title}</h3>
      <p style={{ fontSize: "13px", color: p.color, margin: "0 0 10px", fontWeight: 600 }}>{p.subtitle}</p>
      <p style={{ fontSize: "13px", color: C.textMuted, lineHeight: 1.55, margin: "0 0 14px" }}>{p.problem.slice(0, 110)}...</p>
      <div style={{ display: "flex", flexWrap: "wrap", gap: "5px" }}>
        {p.tech.slice(0, 4).map(t => <Badge key={t} color={p.color}>{t}</Badge>)}
        {p.tech.length > 4 && <Badge color={C.textDim}>+{p.tech.length - 4}</Badge>}
      </div>
    </div>
  );
}

function ProjDetail({ p, onClose }) {
  return (
    <div style={{ position: "fixed", top: 0, left: 0, right: 0, bottom: 0, zIndex: 1000, background: "rgba(0,0,0,0.35)", backdropFilter: "blur(6px)", display: "flex", justifyContent: "center", alignItems: "flex-start", overflowY: "auto", padding: "40px 16px" }} onClick={onClose}>
      <div style={{ background: C.white, borderRadius: "18px", maxWidth: "760px", width: "100%", border: `1px solid ${C.border}`, padding: "36px", boxShadow: "0 20px 60px rgba(0,0,0,0.12)" }} onClick={e => e.stopPropagation()}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "20px" }}>
          <Badge color={p.color}>{p.date} — {p.client}</Badge>
          <button onClick={onClose} style={{ background: C.bg, border: "none", color: C.textMuted, width: "32px", height: "32px", borderRadius: "50%", cursor: "pointer", fontSize: "16px", display: "flex", alignItems: "center", justifyContent: "center" }}>✕</button>
        </div>
        <h2 style={{ fontSize: "28px", fontWeight: 800, color: C.text, margin: "0 0 2px", fontFamily: "'Syne', sans-serif" }}>{p.title}</h2>
        <p style={{ color: p.color, fontSize: "15px", fontWeight: 600, margin: "0 0 20px" }}>{p.subtitle}</p>
        <div style={{ marginBottom: "22px" }}>
          <h4 style={{ color: C.accent, fontSize: "12px", textTransform: "uppercase", letterSpacing: "0.1em", marginBottom: "6px", fontWeight: 700 }}>The Challenge</h4>
          <p style={{ color: C.text, fontSize: "14px", lineHeight: 1.7 }}>{p.problem}</p>
        </div>
        <div style={{ marginBottom: "22px" }}>
          <h4 style={{ color: C.accent, fontSize: "12px", textTransform: "uppercase", letterSpacing: "0.1em", marginBottom: "6px", fontWeight: 700 }}>Solution Architecture</h4>
          <p style={{ color: C.text, fontSize: "14px", lineHeight: 1.7 }}>{p.solution}</p>
        </div>
        <div style={{ marginBottom: "22px" }}>
          <h4 style={{ color: C.accent, fontSize: "12px", textTransform: "uppercase", letterSpacing: "0.1em", marginBottom: "10px", fontWeight: 700 }}>Key Features</h4>
          {p.features.map((f, i) => <div key={i} style={{ display: "flex", gap: "8px", marginBottom: "6px" }}><span style={{ color: p.color, marginTop: "1px" }}>→</span><span style={{ color: C.text, fontSize: "13.5px", lineHeight: 1.5 }}>{f}</span></div>)}
        </div>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: "10px", marginBottom: "22px" }}>
          {p.results.map((r, i) => <MetricBox key={i} metric={r.metric} label={r.label} color={p.color} />)}
        </div>
        <div>
          <h4 style={{ color: C.accent, fontSize: "12px", textTransform: "uppercase", letterSpacing: "0.1em", marginBottom: "10px", fontWeight: 700 }}>Tech Stack</h4>
          <div style={{ display: "flex", flexWrap: "wrap", gap: "6px" }}>{p.tech.map(t => <Badge key={t} color={p.color}>{t}</Badge>)}</div>
        </div>
      </div>
    </div>
  );
}

